// GET /api/admin/payments
exports.getAll = async (req, res, next) => {
  try {
    const { page = 1, limit = 20, search, type } = req.query;
    const offset = (page - 1) * limit;

    let query = `
      SELECT p.*, p.notes as description, m.full_name as member_name, m.card_number
      FROM payments p
      LEFT JOIN members m ON p.member_id = m.id
      WHERE 1=1`;
    const params = [];
    let paramIndex = 1;

    if (search) {
      query += ` AND (m.full_name ILIKE $${paramIndex} OR m.card_number ILIKE $${paramIndex} OR p.notes ILIKE $${paramIndex})`;
      params.push(`%${search}%`);
      paramIndex++;
    }

    if (type && type !== 'all') {
      query += ` AND p.type = $${paramIndex}`;
      params.push(type);
      paramIndex++;
    }

    query += ` ORDER BY p.created_at DESC LIMIT $${paramIndex} OFFSET $${paramIndex + 1}`;
    params.push(parseInt(limit), offset);

    const { rows } = await pool.query(query, params);

    // Get total count with same filters
    let countQuery = `
      SELECT COUNT(*) as total 
      FROM payments p
      LEFT JOIN members m ON p.member_id = m.id
      WHERE 1=1`;
    const countParams = [];
    let countParamIndex = 1;

    if (search) {
      countQuery += ` AND (m.full_name ILIKE $${countParamIndex} OR m.card_number ILIKE $${countParamIndex} OR p.notes ILIKE $${countParamIndex})`;
      countParams.push(`%${search}%`);
      countParamIndex++;
    }

    if (type && type !== 'all') {
      countQuery += ` AND p.type = $${countParamIndex}`;
      countParams.push(type);
      countParamIndex++;
    }

    const { rows: countRows } = await pool.query(countQuery, countParams);

    return res.json({
      success: true,
      data: rows,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: parseInt(countRows[0].total),
        totalPages: Math.ceil(countRows[0].total / limit),
      },
    });
  } catch (error) {
    return next(error);
  }
};

// GET /api/admin/payments/:id
exports.getById = async (req, res, next) => {
  try {
    const { id } = req.params;
    const { rows } = await pool.query('SELECT *, notes as description FROM payments WHERE id = $1', [id]);

    if (rows.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy payment',
      });
    }

    return res.json({
      success: true,
      data: rows[0],
    });
  } catch (error) {
    return next(error);
  }
};

// POST /api/admin/payments
exports.create = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const data = req.body;
    
    // Map description to notes for DB compatibility
    if (data.description !== undefined) {
      data.notes = data.description;
      delete data.description;
    }

    // Auto-generate transaction_id if missing
    if (!data.transaction_id) {
      const typeCode = (data.type || 'PAY').toString().substring(0, 3).toUpperCase();
      data.transaction_id = generateTransactionId(typeCode);
    }

    const fields = Object.keys(data).join(', ');
    const values = Object.keys(data).map((_, i) => `$${i + 1}`).join(', ');
    const params = Object.values(data);

    const { rows } = await client.query(
      `INSERT INTO payments (${fields}) VALUES (${values}) RETURNING *`,
      params
    );

    await client.query('COMMIT');

    return res.status(201).json({
      success: true,
      message: 'Đã tạo payment thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

// PUT /api/admin/payments/:id
exports.update = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { id } = req.params;
    const data = req.body;

    // Map description to notes for DB compatibility
    if (data.description !== undefined) {
      data.notes = data.description;
      delete data.description;
    }

    // Check if exists
    const { rows: existing } = await client.query('SELECT * FROM payments WHERE id = $1', [id]);
    if (existing.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy payment',
      });
    }

    // Build update query
    const updateFields = [];
    const params = [];
    let paramIndex = 1;

    Object.keys(data).forEach(key => {
      if (data[key] !== undefined) {
        updateFields.push(`${key} = $${paramIndex++}`);
        params.push(data[key]);
      }
    });

    if (updateFields.length > 0) {
      params.push(id);
      await client.query(
        `UPDATE payments SET ${updateFields.join(', ')} WHERE id = $${paramIndex}`,
        params
      );
    }

    await client.query('COMMIT');

    const { rows } = await client.query('SELECT *, notes as description FROM payments WHERE id = $1', [id]);

    return res.json({
      success: true,
      message: 'Đã cập nhật payment thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

// DELETE /api/admin/payments/:id
exports.remove = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { id } = req.params;

    const { rows } = await client.query('SELECT * FROM payments WHERE id = $1', [id]);
    if (rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy payment',
      });
    }

    await client.query('DELETE FROM payments WHERE id = $1', [id]);

    await client.query('COMMIT');

    return res.json({
      success: true,
      message: 'Đã xóa payment thành công',
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};
